import{c as a,Q as d,j as e,m as r}from"./chunks/framework.iD28w_5a.js";const _=JSON.parse('{"title":"Hands-on 动手实践","description":"","frontmatter":{},"headers":[],"relativePath":"hands-on/index.md","filePath":"hands-on/index.md","lastUpdated":1779686691000}'),n={name:"hands-on/index.md"};function o(h,t,i,l,s,c){return d(),e("div",null,[...t[0]||(t[0]=[r('<h1 id="hands-on-动手实践" tabindex="-1">Hands-on 动手实践 <a class="header-anchor" href="#hands-on-动手实践" aria-label="Permalink to &quot;Hands-on 动手实践&quot;">​</a></h1><p>OS 作业式引导教程。只给设计描述和验证命令，<strong>绝不展示代码</strong>——你需要自己动手实现。</p><h2 id="内容结构" tabindex="-1">内容结构 <a class="header-anchor" href="#内容结构" aria-label="Permalink to &quot;内容结构&quot;">​</a></h2><p>按编号顺序组织，每个编号对应一个内核功能模块，每篇聚焦一个功能点：</p><table tabindex="0"><thead><tr><th>编号</th><th>模块</th><th>说明</th></tr></thead><tbody><tr><td>000</td><td>环境搭建</td><td>工具链配置、QEMU 安装、项目骨架</td></tr><tr><td>001</td><td>Real Mode 引导</td><td>BIOS 中断、MBR 结构、磁盘读取</td></tr><tr><td>002</td><td>GDT 与保护模式</td><td>段描述符、GDT 加载、模式切换</td></tr><tr><td>003</td><td>Long Mode</td><td>页表、CR3 配置、64 位模式入口</td></tr><tr><td>004</td><td>内核加载</td><td>Multiboot2、ELF 解析、内核入口</td></tr><tr><td>005+</td><td>内核功能</td><td>中断、内存管理、驱动、文件系统……</td></tr></tbody></table><h2 id="适合谁" tabindex="-1">适合谁 <a class="header-anchor" href="#适合谁" aria-label="Permalink to &quot;适合谁&quot;">​</a></h2><ul><li>有一定 C/C++ 基础，想从零写一个 OS 的开发者</li><li>了解 x86 基本概念（寄存器、内存分段）即可开始</li><li>不需要操作系统课程基础——每篇会交代必要的背景知识</li></ul><h2 id="推荐阅读路径" tabindex="-1">推荐阅读路径 <a class="header-anchor" href="#推荐阅读路径" aria-label="Permalink to &quot;推荐阅读路径&quot;">​</a></h2><p>按编号顺序阅读，从 <a href="./000-env-toolchain-1">环境搭建（000-1）</a> 开始。每篇末尾有「验证」步骤，通过即可进入下一篇。</p><p>如果遇到问题，可以对照同编号的 <a href="/cinux/read-through/">Read-through</a> 篇章查看参考实现。</p>',10)])])}const u=a(n,[["render",o]]);export{_ as __pageData,u as default};
